using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ── CalculateTotal: inline data with [DataRow] ──────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0,  10.00,  DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0,  20.00,  DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00,  DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62,  DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00,  5, 0.10, 0.00,   DisplayName = "Zero price yields zero total")]
    [DataRow(99.99, 0, 0.05, 0.00,   DisplayName = "Zero quantity yields zero total")]
    [DataRow(10.00, 1, 1.0,  20.00,  DisplayName = "100% tax doubles the price")]
    public void CalculateTotal_WithVariousInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expectedTotal)
    {
        var result = _calculator.CalculateTotal(
            (decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expectedTotal, result);
    }

    // ── CalculateTotal: complex cases with [DynamicData] ────────────────

    public static IEnumerable<object[]> BulkOrderCases =>
    [
        [100.00m, 100, 0.07m, 10700.00m],   // Large quantity
        [0.01m,   1,   0.0m,  0.01m],        // Minimum meaningful price
        [9999.99m, 1,  0.15m, 11499.9885m],  // High price with tax
    ];

    [TestMethod]
    [DynamicData(nameof(BulkOrderCases))]
    public void CalculateTotal_BulkOrders_ReturnsExpectedTotal(
        decimal unitPrice, int quantity, decimal taxRate, decimal expectedTotal)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expectedTotal, result);
    }

    // ── CalculateTotal: invalid inputs ──────────────────────────────────

    [TestMethod]
    [DataRow(-1.0, 1, 0.1, DisplayName = "Negative unit price")]
    public void CalculateTotal_NegativeUnitPrice_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(
                (decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.0, -1, 0.1, DisplayName = "Negative quantity")]
    public void CalculateTotal_NegativeQuantity_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(
                (decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.0, 1, -0.01, DisplayName = "Tax rate below 0")]
    [DataRow(10.0, 1,  1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(
                (decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // ── ApplyDiscount: inline data with [DataRow] ───────────────────────

    [TestMethod]
    [DataRow(100.00, 0.0,   100.00, DisplayName = "0% discount — full price")]
    [DataRow(100.00, 10.0,  90.00,  DisplayName = "10% discount")]
    [DataRow(100.00, 50.0,  50.00,  DisplayName = "50% discount")]
    [DataRow(100.00, 100.0, 0.00,   DisplayName = "100% discount — free")]
    [DataRow(59.99,  15.0,  50.9915,DisplayName = "Fractional result")]
    public void ApplyDiscount_WithVariousPercents_ReturnsExpectedPrice(
        double price, double discountPercent, double expectedPrice)
    {
        var result = _calculator.ApplyDiscount(
            (decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expectedPrice, result);
    }

    // ── ApplyDiscount: edge-case matrix via [DynamicData] method source ─

    public static IEnumerable<object[]> DiscountEdgeCases()
    {
        // Discount applied to zero price is always zero
        yield return [0.00m, 0.0m,   0.00m];
        yield return [0.00m, 50.0m,  0.00m];
        yield return [0.00m, 100.0m, 0.00m];

        // Very small discount
        yield return [200.00m, 0.01m, 199.98m];
    }

    [TestMethod]
    [DynamicData(nameof(DiscountEdgeCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_EdgeCases_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expectedPrice)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expectedPrice, result);
    }

    // ── ApplyDiscount: invalid inputs ───────────────────────────────────

    [TestMethod]
    [DataRow(100.0, -1.0,  DisplayName = "Negative discount")]
    [DataRow(100.0, 100.01, DisplayName = "Discount above 100%")]
    public void ApplyDiscount_InvalidPercent_Throws(
        double price, double discountPercent)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(
                (decimal)price, (decimal)discountPercent));
    }
}

